class Solution:
    def insert(self, intervals, newInterval):
        events = list(intervals) + [newInterval]
        events.sort()
        res = []
        for s, e in events:
            if res and s <= res[-1][1]:
                if e > res[-1][1]:
                    res[-1][1] = e
            else:
                res.append([s, e])
        return res

